export const constitucion = {
  titulo: 'Constitución de la República de Panamá',
  descripcion: 'Constitución Política de 1972, reformada por los Actos Reformatorios de 1983, 1994 y 2004. Es la norma suprema del ordenamiento jurídico panameño.',
  info: {
    anio: '1972',
    ultimaReforma: '2004',
    importancia: 'Norma suprema del ordenamiento jurídico panameño',
    conceptosClave: ['Soberanía', 'Derechos Humanos', 'División de Poderes', 'Garantías Constitucionales'],
  },
  articulos: [
    { id: 'CN-1', articulo: 1, titulo: 'Soberanía', contenido: 'La Nación panameña está organizada en Estado soberano e independiente, cuya denominación es República de Panamá. El poder público emana del pueblo y se ejerce por medio de sus representantes.', libro: 'Título I', categoria: 'Disposiciones Fundamentales' },
    { id: 'CN-2', articulo: 2, titulo: 'División de Poderes', contenido: 'El Gobierno de la República de Panamá se ejerce por tres órganos: el Legislativo, el Ejecutivo y el Judicial, coordinados entre sí y con funciones separadas pero armónicas. Ninguno de ellos puede arrogarse funciones que no le corresponden.', libro: 'Título I', categoria: 'Disposiciones Fundamentales' },
    { id: 'CN-3', articulo: 3, titulo: 'Territorio Nacional', contenido: 'El territorio de la República de Panamá comprende la superficie terrestre, el mar territorial, la plataforma continental, el subsuelo y el espacio aéreo entre Colombia y Costa Rica. La ley determinará las áreas marítimas y aéreas bajo soberanía nacional.', libro: 'Título I', categoria: 'Disposiciones Fundamentales' },
    { id: 'CN-4', articulo: 4, titulo: 'Relaciones Internacionales', contenido: 'Panamá acata las normas del Derecho Internacional y propugna la solución pacífica de las controversias internacionales. Rechaza la guerra como instrumento de solución de conflictos.', libro: 'Título I', categoria: 'Disposiciones Fundamentales' },
    { id: 'CN-5', articulo: 5, titulo: 'Nacionalidad Panameña', contenido: 'Son panameños por nacimiento: los nacidos en el territorio nacional, los hijos de padre o madre panameños nacidos en el extranjero, y los adoptados por panameños. Son panameños por naturalización los que adquieran la nacionalidad conforme a la ley.', libro: 'Título II', categoria: 'Nacionalidad' },
    { id: 'CN-17', articulo: 17, titulo: 'Derechos y Garantías Fundamentales', contenido: 'Los derechos y garantías que consagra la Constitución se consideran mínimos y no excluyen otros que se refieran a los derechos fundamentales de la persona. Las autoridades están obligadas a protegerlos y hacerlos efectivos.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-18', articulo: 18, titulo: 'Deberes del Estado', contenido: 'Los servidores públicos están al servicio del Estado y de la comunidad. Responden por la violación de los derechos de las personas y por el incumplimiento de sus deberes.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-19', articulo: 19, titulo: 'Igualdad ante la Ley', contenido: 'No habrá fueros personales ni discriminación por razón de raza, nacimiento, discapacidad, clase social, sexo, religión o ideas políticas. La ley determinará las sanciones por violación de este principio.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-20', articulo: 20, titulo: 'Debido Proceso', contenido: 'Toda persona tiene derecho a ser oída en un plazo razonable por un tribunal competente, independiente e imparcial. Nadie puede ser juzgado sino por autoridad competente y conforme a los trámites legales.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-21', articulo: 21, titulo: 'Libertad Personal', contenido: 'Nadie puede ser detenido sino por mandamiento escrito de autoridad judicial, salvo flagrancia. La detención preventiva no excederá de 48 horas, y dentro de ese término se pondrá al detenido a disposición de la autoridad judicial.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-22', articulo: 22, titulo: 'Inviolabilidad de la Vivienda', contenido: 'La vivienda es inviolable. Nadie puede penetrar en ella sin consentimiento del morador o sin mandamiento judicial, salvo delito flagrante. Las comunicaciones privadas son inviolables.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-23', articulo: 23, titulo: 'Habeas Corpus', contenido: 'Toda persona detenida ilegalmente tiene derecho a solicitar Habeas Corpus ante el Tribunal Superior de Justicia. El procedimiento es preferente y sumario, y la autoridad judicial debe resolverlo en un término no mayor de 24 horas.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-24', articulo: 24, titulo: 'Libertad de Expresión', contenido: 'Toda persona tiene derecho a expresar libremente su pensamiento mediante la palabra, la escritura o cualquier otro medio. No hay censura previa, pero la ley establecerá las responsabilidades por el abuso de este derecho.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-25', articulo: 25, titulo: 'Libertad de Reunión', contenido: 'Toda persona tiene derecho de reunirse pacíficamente y sin armas para fines lícitos, sin necesidad de permiso previo. En lugares públicos se requerirá aviso previo a la autoridad.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-26', articulo: 26, titulo: 'Libertad de Asociación', contenido: 'Toda persona tiene derecho a formar asociaciones para fines lícitos, sin necesidad de autorización previa. Las asociaciones deben inscribirse en un registro público.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-27', articulo: 27, titulo: 'Libertad de Culto', contenido: 'Toda persona puede profesar libremente su religión y practicar sus creencias sin más limitaciones que el orden público y el respeto a la moral. Las iglesias son independientes del Estado.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-28', articulo: 28, titulo: 'Derecho de Petición', contenido: 'Toda persona tiene derecho a presentar peticiones respetuosas a las autoridades y a obtener pronta resolución. La autoridad debe resolver dentro del término legal, so pena de incurrir en responsabilidad.', libro: 'Título III', categoria: 'Derechos y Garantías' },
    { id: 'CN-29', articulo: 29, titulo: 'Derecho a la Propiedad Privada', contenido: 'Se garantiza la propiedad privada adquirida conforme a la ley. La expropiación solo procede por causa de utilidad pública o interés social, mediante indemnización previa y justa.', libro: 'Título III', categoria: 'Derechos Económicos' },
    { id: 'CN-30', articulo: 30, titulo: 'Libertad de Trabajo', contenido: 'Toda persona tiene derecho al trabajo y a dedicarse a la actividad económica de su preferencia, sin más limitaciones que las establecidas por la ley. Nadie puede ser obligado a trabajar gratuitamente.', libro: 'Título III', categoria: 'Derechos Económicos' },
    { id: 'CN-40', articulo: 40, titulo: 'Derecho a la Salud', contenido: 'Toda persona tiene derecho a la salud. El Estado garantiza el acceso universal a los servicios de salud pública, y la ley determinará la forma de prestarlos.', libro: 'Título III', categoria: 'Derechos Sociales' },
    { id: 'CN-41', articulo: 41, titulo: 'Derecho a la Educación', contenido: 'La educación es un derecho de la persona y un deber del Estado. La educación primaria es obligatoria y gratuita. El Estado fomentará la educación científica, técnica y profesional.', libro: 'Título III', categoria: 'Derechos Sociales' },
    { id: 'CN-42', articulo: 42, titulo: 'Libertad Sindical', contenido: 'Los trabajadores tienen derecho a la sindicalización voluntaria y a la negociación colectiva. La ley regulará el ejercicio de estos derechos y garantizará el fuero sindical.', libro: 'Título III', categoria: 'Derechos Sociales' },
    { id: 'CN-100', articulo: 100, titulo: 'Organo Legislativo', contenido: 'El Organo Legislativo está constituido por la Asamblea Nacional, elegida por votación popular directa para un período de cinco años. La Asamblea se compone de diputados en número proporcional a la población.', libro: 'Título V', categoria: 'Organización del Estado' },
    { id: 'CN-101', articulo: 101, titulo: 'Funciones de la Asamblea Nacional', contenido: 'Corresponde a la Asamblea Nacional: expedir leyes, aprobar el presupuesto del Estado, ratificar tratados internacionales, elegir a los magistrados de la Corte Suprema, y ejercer control político sobre el Órgano Ejecutivo.', libro: 'Título V', categoria: 'Organización del Estado' },
    { id: 'CN-102', articulo: 102, titulo: 'Iniciativa Legislativa', contenido: 'Las leyes pueden ser iniciadas por los diputados, el Presidente de la República, la Corte Suprema de Justicia, y por iniciativa popular mediante petición firmada por el 1% del electorado.', libro: 'Título V', categoria: 'Organización del Estado' },
    { id: 'CN-150', articulo: 150, titulo: 'Organo Ejecutivo', contenido: 'El Organo Ejecutivo está constituido por el Presidente de la República y los Ministros de Estado. El Presidente es elegido por votación popular directa para un período de cinco años sin reelección inmediata.', libro: 'Título VI', categoria: 'Organización del Estado' },
    { id: 'CN-151', articulo: 151, titulo: 'Funciones del Presidente', contenido: 'El Presidente de la República ejerce la jefatura del Estado y del Gobierno, representa a la Nación, dirige la administración pública, sanciona y promulga las leyes, y nombra a los Ministros de Estado.', libro: 'Título VI', categoria: 'Organización del Estado' },
    { id: 'CN-200', articulo: 200, titulo: 'Organo Judicial', contenido: 'El Organo Judicial está constituido por la Corte Suprema de Justicia, los tribunales superiores y los juzgados. La función jurisdiccional se ejerce con independencia y los jueces son independientes en el ejercicio de sus funciones.', libro: 'Título VII', categoria: 'Organización del Estado' },
    { id: 'CN-201', articulo: 201, titulo: 'Corte Suprema de Justicia', contenido: 'La Corte Suprema de Justicia es el máximo tribunal de la República. Está integrada por nueve magistrados designados por el Presidente de la República con aprobación de la Asamblea Nacional, para períodos de diez años.', libro: 'Título VII', categoria: 'Organización del Estado' },
    { id: 'CN-202', articulo: 202, titulo: 'Jurisdicción de la Corte Suprema', contenido: 'La Corte Suprema conoce de los recursos de casación, habeas corpus, amparo de garantías constitucionales, inconstitucionalidad de leyes, y los conflictos entre órganos del Estado.', libro: 'Título VII', categoria: 'Organización del Estado' },
    { id: 'CN-203', articulo: 203, titulo: 'Amparo de Garantías Constitucionales', contenido: 'Toda persona puede interponer acción de amparo de garantías constitucionales contra cualquier orden, acto o disposición de autoridad que viole los derechos constitucionales. El procedimiento es preferente y sumario.', libro: 'Título VII', categoria: 'Organización del Estado' },
    { id: 'CN-204', articulo: 204, titulo: 'Acción de Inconstitucionalidad', contenido: 'Cuando una ley o decreto viole un precepto constitucional, cualquier persona puede solicitar su declaratoria de inconstitucionalidad ante la Corte Suprema. La decisión de la Corte tiene efecto general y es definitiva.', libro: 'Título VII', categoria: 'Organización del Estado' },
    { id: 'CN-300', articulo: 300, titulo: 'División Política', contenido: 'La República se divide políticamente en provincias, estas en distritos y estos en corregimientos. La ley fijará su número, límites y organización. La creación de nuevas provincias requiere aprobación legislativa.', libro: 'Título IX', categoria: 'Organización Territorial' },
    { id: 'CN-301', articulo: 301, titulo: 'Régimen Municipal', contenido: 'Los municipios son autónomos política, administrativa y económicamente. Su gobierno corresponde al alcalde y al concejo municipal, elegidos por votación popular para períodos de cinco años.', libro: 'Título IX', categoria: 'Organización Territorial' },
  ],
};

export const codigoFamilia = {
  titulo: 'Código de la Familia de la República de Panamá',
  descripcion: 'Ley 3 de 17 de mayo de 1994, que regula las relaciones jurídicas derivadas de la familia, los menores y las instituciones familiares en Panamá.',
  info: {
    anio: '1994',
    ultimaReforma: '2017',
    importancia: 'Regula las relaciones familiares y la protección de menores',
    conceptosClave: ['Matrimonio', 'Divorcio', 'Filiación', 'Patria Potestad', 'Alimentos', 'Adopción'],
  },
  articulos: [
    { id: 'CF-1', articulo: 1, titulo: 'Objeto del Código de la Familia', contenido: 'El presente Código tiene por objeto regular las relaciones jurídicas derivadas de la familia y de los menores, así como proteger los derechos fundamentales de sus miembros dentro del marco de la Constitución y las leyes panameñas.', libro: 'Libro I', categoria: 'Disposiciones Generales' },
    { id: 'CF-2', articulo: 2, titulo: 'Protección Estatal de la Familia', contenido: 'El Estado protege a la familia como institución fundamental de la sociedad panameña. La familia debe fundarse en el respeto mutuo, la solidaridad, la igualdad de derechos y deberes entre sus integrantes, y el interés superior del menor.', libro: 'Libro I', categoria: 'Disposiciones Generales' },
    { id: 'CF-3', articulo: 3, titulo: 'Interés Superior del Menor', contenido: 'En todas las decisiones que afecten a un menor, ya sean tomadas por autoridades públicas, tribunales o instituciones privadas, se considerará primordialmente el interés superior del niño, niña o adolescente.', libro: 'Libro I', categoria: 'Disposiciones Generales' },
    { id: 'CF-10', articulo: 10, titulo: 'Matrimonio Civil', contenido: 'El matrimonio civil es la unión voluntaria entre un hombre y una mujer, con aptitud legal, para hacer vida en común. Debe celebrarse ante la autoridad competente del Registro Civil con la presencia de dos testigos hábiles.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-11', articulo: 11, titulo: 'Requisitos del Matrimonio', contenido: 'Para contraer matrimonio se requiere: ser mayor de 18 años, consentimiento libre y voluntario manifestado ante la autoridad competente, y la presencia de dos testigos mayores de edad. Los menores de 18 años requieren autorización de sus padres.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-12', articulo: 12, titulo: 'Impedimentos Matrimoniales', contenido: 'Son impedimentos para contraer matrimonio: el vínculo matrimonial anterior no disuelto, el parentesco en línea recta por consanguinidad o afinidad, el parentesco colateral hasta el tercer grado, y la falta de consentimiento libre.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-13', articulo: 13, titulo: 'Divorcio por Mutuo Acuerdo', contenido: 'El divorcio por mutuo acuerdo puede solicitarse después de un año de matrimonio. Los cónyuges deben presentar un acuerdo integral que regule la distribución de bienes, la custodia de los hijos, la pensión alimentaria y la vivienda familiar.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-14', articulo: 14, titulo: 'Divorcio por Causales', contenido: 'Son causales de divorcio: el adulterio, la sevicia o maltratos graves, las amenazas graves contra la vida o la integridad, el abandono voluntario del hogar, la separación de hecho por más de dos años, y la incompatibilidad de caracteres.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-20', articulo: 20, titulo: 'Unión de Hecho', contenido: 'La unión de hecho estable y permanente entre un hombre y una mujer, con capacidad legal, que mantengan hogar común por más de cinco años, produce efectos legales similares al matrimonio en cuanto a derechos patrimoniales y sucesorios.', libro: 'Libro II', categoria: 'Matrimonio' },
    { id: 'CF-30', articulo: 30, titulo: 'Filiación', contenido: 'La filiación es la relación jurídica entre padres e hijos. Puede ser por naturaleza o por adopción. Todos los hijos tienen iguales derechos y deberes, sin importar su filiación.', libro: 'Libro III', categoria: 'Filiación' },
    { id: 'CF-31', articulo: 31, titulo: 'Reconocimiento Voluntario', contenido: 'El reconocimiento de los hijos es un acto voluntario que puede hacerse en el Registro Civil, en testamento, en escritura pública o en declaración judicial. Es irrevocable y no admite modalidades.', libro: 'Libro III', categoria: 'Filiación' },
    { id: 'CF-32', articulo: 32, titulo: 'Investigación Judicial de Paternidad', contenido: 'Toda persona tiene derecho a investigar judicialmente su filiación. La acción de investigación de paternidad es imprescriptible y puede ejercerse mediante pruebas biológicas, documentales o testimoniales.', libro: 'Libro III', categoria: 'Filiación' },
    { id: 'CF-40', articulo: 40, titulo: 'Patria Potestad', contenido: 'La patria potestad comprende el conjunto de derechos y obligaciones que corresponden a los padres respecto de sus hijos menores de edad, incluyendo el cuidado, la protección, la educación, la representación legal y la administración de sus bienes.', libro: 'Libro IV', categoria: 'Patria Potestad' },
    { id: 'CF-41', articulo: 41, titulo: 'Suspensión de la Patria Potestad', contenido: 'La patria potestad se suspende por: demencia declarada judicialmente, ausencia injustificada por más de seis meses, maltrato grave al hijo, abandono del hogar conyugal, y condena penal a prisión por más de tres años.', libro: 'Libro IV', categoria: 'Patria Potestad' },
    { id: 'CF-42', articulo: 42, titulo: 'Custodia Compartida', contenido: 'En caso de separación o divorcio, la custodia de los hijos se determinará considerando primordialmente el interés superior del menor. Se favorecerá la custodia compartida cuando sea posible y beneficiosa para el menor.', libro: 'Libro IV', categoria: 'Patria Potestad' },
    { id: 'CF-50', articulo: 50, titulo: 'Obligación Alimentaria', contenido: 'Los padres deben alimentos a sus hijos y los hijos a sus padres cuando estos no puedan mantenerse por sí mismos. La obligación alimentaria comprende alimentación, vivienda, vestido, educación, salud, recreación y formación integral.', libro: 'Libro V', categoria: 'Alimentos' },
    { id: 'CF-51', articulo: 51, titulo: 'Fijación de la Cuota Alimentaria', contenido: 'La cuota alimentaria se fija considerando las necesidades del alimentario y las posibilidades económicas del obligado. No podrá exceder del 50% del ingreso del obligado. El juez puede ajustarla periódicamente.', libro: 'Libro V', categoria: 'Alimentos' },
    { id: 'CF-52', articulo: 52, titulo: 'Proceso de Alimentos', contenido: 'El proceso de alimentos es preferente y sumario. El juez puede ordenar el pago provisional de alimentos desde la admisión de la demanda. El incumplimiento reiterado puede dar lugar a sanciones penales.', libro: 'Libro V', categoria: 'Alimentos' },
    { id: 'CF-60', articulo: 60, titulo: 'Adopción', contenido: 'La adopción es una institución que tiene por objeto proporcionar una familia idónea y permanente al menor que carece de ella. La adopción se constituye por resolución judicial y es irrevocable.', libro: 'Libro VI', categoria: 'Adopción' },
    { id: 'CF-61', articulo: 61, titulo: 'Requisitos de los Adoptantes', contenido: 'Para adoptar se requiere: ser mayor de 25 años, tener capacidad legal plena, estar en condiciones morales y económicas adecuadas, tener diferencia de edad de al menos 15 años con el adoptado, y ser evaluado por el equipo psicosocial.', libro: 'Libro VI', categoria: 'Adopción' },
    { id: 'CF-70', articulo: 70, titulo: 'Protección de Menores en Riesgo', contenido: 'El Estado protegerá a los menores en situación de riesgo social mediante medidas de protección que incluyen: orientación a la familia, apoyo socioeconómico, colocación familiar, acogimiento residencial y adopción cuando sea necesario.', libro: 'Libro VII', categoria: 'Protección de Menores' },
    { id: 'CF-71', articulo: 71, titulo: 'Maltrato y Abuso Infantil', contenido: 'Todo acto de maltrato físico, psicológico, sexual o negligencia contra un menor será sancionado conforme a la ley. La autoridad competente debe intervenir de oficio y garantizar la protección inmediata del menor.', libro: 'Libro VII', categoria: 'Protección de Menores' },
    { id: 'CF-72', articulo: 72, titulo: 'Violencia Doméstica', contenido: 'La violencia intrafamiliar o doméstica es todo acto de agresión física, psicológica o sexual cometido por un miembro de la familia contra otro. Las víctimas tienen derecho a medidas de protección inmediatas.', libro: 'Libro VII', categoria: 'Protección de Menores' },
  ],
};
export const codigoFiscal = {
  titulo: 'Código Fiscal de la República de Panamá',
  descripcion: 'Ley 8 de 1956, Código Fiscal de la República de Panamá, modificado por Ley 57 de 2021 y otras disposiciones tributarias.',
  info: {
    anio: '1956',
    ultimaReforma: '2021',
    importancia: 'Regula el sistema tributario y fiscal panameño',
    conceptosClave: ['ISR', 'ITBMS', 'Impuesto de Inmueble', 'Aduanas', 'Facturación Electrónica'],
  },
  articulos: [
    { id: 'CFI-1', articulo: 1, titulo: 'Principios del Sistema Tributario', contenido: 'El sistema tributario panameño se fundamenta en los principios de legalidad, igualdad, equidad, capacidad contributiva y no confiscatoriedad. Los tributos solo pueden crearse, modificarse o suprimirse mediante ley formal.', libro: 'Libro I', categoria: 'Principios Tributarios' },
    { id: 'CFI-2', articulo: 2, titulo: 'Impuesto sobre la Renta (ISR)', contenido: 'Toda persona natural o jurídica que obtenga ingresos de fuente panameña está sujeta al impuesto sobre la renta. El impuesto se calcula sobre la renta neta gravable, que es la renta bruta menos las deducciones permitidas por la ley.', libro: 'Libro II', categoria: 'Impuesto sobre la Renta' },
    { id: 'CFI-3', articulo: 3, titulo: 'Renta de Fuente Panameña', contenido: 'Se consideran de fuente panameña las rentas provenientes de bienes situados en el territorio nacional, de actividades desarrolladas en Panamá, de créditos utilizados en el país, y de bienes intangibles explotados en Panamá.', libro: 'Libro II', categoria: 'Impuesto sobre la Renta' },
    { id: 'CFI-4', articulo: 4, titulo: 'Tarifa del ISR para Personas Jurídicas', contenido: 'Las personas jurídicas pagan el 25% sobre su renta neta gravable. Las empresas con ingresos anuales inferiores a B/.1,500,000 pagan una tasa progresiva que inicia en 15% para los primeros B/.50,000 de renta neta.', libro: 'Libro II', categoria: 'Impuesto sobre la Renta' },
    { id: 'CFI-5', articulo: 5, titulo: 'Tarifa del ISR para Personas Naturales', contenido: 'Las personas naturales pagan tarifas progresivas: 0% hasta B/.11,000 de renta neta, 15% sobre el excedente de B/.11,001 hasta B/.50,000, y 27% sobre el excedente de B/.50,001 en adelante.', libro: 'Libro II', categoria: 'Impuesto sobre la Renta' },
    { id: 'CFI-6', articulo: 6, titulo: 'ITBMS - Impuesto a la Transferencia', contenido: 'El Impuesto a la Transferencia de Bienes Muebles y Servicios (ITBMS) es del 7% y se aplica a la venta de bienes muebles, la prestación de servicios, la importación de bienes y la construcción en el territorio nacional.', libro: 'Libro III', categoria: 'ITBMS' },
    { id: 'CFI-7', articulo: 7, titulo: 'Exenciones del ITBMS', contenido: 'Están exentos del ITBMS: los alimentos básicos de la canasta familiar, los medicamentos, los libros y revistas, los servicios educativos, los servicios de salud, las exportaciones, el transporte público, y los servicios financieros.', libro: 'Libro III', categoria: 'ITBMS' },
    { id: 'CFI-8', articulo: 8, titulo: 'Impuesto de Inmueble', contenido: 'El impuesto de inmueble se aplica anualmente sobre el valor catastral de la propiedad inmueble. La tasa es del 2.10% para propiedades urbanas y del 1.05% para propiedades rurales.', libro: 'Libro IV', categoria: 'Impuesto de Inmueble' },
    { id: 'CFI-9', articulo: 9, titulo: 'Exención del Impuesto de Inmueble', contenido: 'Están exentos del impuesto de inmueble: las propiedades del Estado, las iglesias, los partidos políticos, las embajadas, y las viviendas con valor catastral de hasta B/.30,000.', libro: 'Libro IV', categoria: 'Impuesto de Inmueble' },
    { id: 'CFI-10', articulo: 10, titulo: 'Impuesto de Inmueble Progresivo', contenido: 'Las propiedades con valor catastral superior a B/.300,000 pagan una tasa progresiva adicional: 0.5% sobre el excedente entre B/.300,001 y B/.700,000, y 0.7% sobre el excedente superior a B/.700,000.', libro: 'Libro IV', categoria: 'Impuesto de Inmueble' },
    { id: 'CFI-11', articulo: 11, titulo: 'Arancel de Aduanas', contenido: 'Los derechos de importación se aplican a las mercancías que ingresan al territorio nacional conforme al Arancel de Aduanas vigente. Las tasas varían según la clasificación arancelaria de cada producto.', libro: 'Libro V', categoria: 'Aduanas' },
    { id: 'CFI-12', articulo: 12, titulo: 'Zonas Francas y Regímenes Especiales', contenido: 'Las empresas instaladas en zonas francas gozan de exención del impuesto sobre la renta por ingresos de fuente extranjera, exención de aranceles de importación y exportación, y otros beneficios fiscales.', libro: 'Libro VI', categoria: 'Regímenes Especiales' },
    { id: 'CFI-13', articulo: 13, titulo: 'Sedes de Empresas Multinacionales (SEM)', contenido: 'Las sedes de empresas multinacionales establecidas en Panamá gozan de exención del impuesto sobre la renta por los ingresos provenientes de servicios prestados desde Panamá a empresas del mismo grupo en el extranjero.', libro: 'Libro VI', categoria: 'Regímenes Especiales' },
    { id: 'CFI-14', articulo: 14, titulo: 'Retenciones en la Fuente', contenido: 'Los empleadores deben retener el impuesto sobre la renta de sus empleados mensualmente y pagarlo a la Dirección General de Ingresos. También están sujetos a retención los pagos a profesionales, las comisiones y los intereses.', libro: 'Libro VII', categoria: 'Administración Tributaria' },
    { id: 'CFI-15', articulo: 15, titulo: 'Declaración de Renta Anual', contenido: 'Las personas naturales y jurídicas deben presentar declaración de renta anual dentro de los tres meses siguientes al cierre del año fiscal. La declaración debe incluir todos los ingresos, deducciones y el cálculo del impuesto.', libro: 'Libro VII', categoria: 'Administración Tributaria' },
    { id: 'CFI-16', articulo: 16, titulo: 'Facturación Electrónica', contenido: 'La facturación electrónica es obligatoria en Panamá. Los contribuyentes deben emitir comprobantes fiscales electrónicos autorizados por la DGI, que garantizan la trazabilidad de las transacciones comerciales.', libro: 'Libro VII', categoria: 'Administración Tributaria' },
    { id: 'CFI-17', articulo: 17, titulo: 'Prescripción de la Obligación Tributaria', contenido: 'La obligación tributaria prescribe a los 5 años contados desde la fecha en que el tributo era exigible. La prescripción se interrumpe por requerimiento de pago, fiscalización o reconocimiento de la deuda.', libro: 'Libro VII', categoria: 'Administración Tributaria' },
    { id: 'CFI-18', articulo: 18, titulo: 'Infracciones y Sanciones Tributarias', contenido: 'La evasión fiscal, la defraudación tributaria y el incumplimiento de obligaciones formales serán sancionados con multas del 50% al 200% del tributo omitido, sin perjuicio de las acciones penales correspondientes.', libro: 'Libro VIII', categoria: 'Infracciones y Sanciones' },
    { id: 'CFI-19', articulo: 19, titulo: 'Fiscalización Tributaria', contenido: 'La Dirección General de Ingresos puede fiscalizar a los contribuyentes mediante auditorías, requerimientos de información y cruces de datos. El contribuyente debe colaborar y proporcionar la documentación requerida.', libro: 'Libro VIII', categoria: 'Infracciones y Sanciones' },
  ],
};

